| issue        = [[:en:Emperor Suinin|Emperor Suinin]] [[Izanomawaka]] [[Kunikatahime]] [[Chijitsukuyamatohime]]  [[Igahime]] [[Yamatohiko]]
| father       = {{ill|Ōhiko-no-Mikoto|lt=Ōhiko-no-Mikoto|lt=Prince Ohiko|ja|大彦命|1=Ōhiko-no-Mikoto|qq=draft|12=simple|13=User:Immanuelle/Prince Ohiko|qq=}}
| succession1  = [[:en:Empress Dowager of Japan|Empress Dowager of Japan]]
| reign1       = 29 BC-?
| predecessor1 = Ikagashikome
| successor1   = [[Yasakairi-hime]]
